def flip_case(string: str) -> str:
    """ For a given string, flip lowercase characters to uppercase and uppercase to lowercase.
    >>> flip_case('Hello')
    'hELLO'
    """
    new_string = []
    for i in string:
        if i.islower():
            new_string.append(i.upper())
        else:
            new_string.append(i.lower())
    return ''.join(new_string)

