    * sort_array([2, 4, 3, 0, 1, 5, 6]) => [6, 5, 4, 3, 2, 1, 0]
    """
    sum1 = sum(array[0::2])
    sum2 = sum(array[1::2])
    result = array[::]
    if sum1 > sum2:
        for i in range(1, len(array) - 1, 2):
            for j in range(i - 1, -1, -1):
                if result[j] > result[j + 1]:
                    result[j], result[j + 1] = result[j + 1], result[j]
            for j in range(i + 1, len(array)):
                if result[j] < result[j - 1]:
                    result[j], result[j - 1] = result[j - 1], result[j]
    else:
