    histogram('a b c a b') == {'a': 2, 'b': 2}
    histogram('b b b b a') == {'b': 4}
    histogram('') == {}

    """
    hist = {}
    for letter in test.split(' '):
        hist[letter] = hist.get(letter, 0) + 1

    max_count = max(hist.values())
    max_count_values = [key for key, value in hist.items() if value == max_count]

    return dict([key, value] for key, value in hist.items() if value == max_count)

